package main

import (
	"context"
	"sync"
)

func Sum(ctx context.Context, nums []int) int {
	var mu sync.Mutex
	total := 0
	var wg sync.WaitGroup
	for _, n := range nums {
		wg.Add(1)
		go func(n int) {
			defer wg.Done()
			mu.Lock()
			total += n
			mu.Unlock()
		}(n)
	}
	wg.Wait()
	return total
}

